memberdef.initializer:
static const struct shell_static_entry shell_##name[] = {	\
	__VA_ARGS__						\
};								\
static const union shell_cmd_entry name = {			\
	.entry = shell_##name					\
}

detaileddescription.para:
_name



Name of the dictionary subcommand set 




_handler



Command handler common for all dictionary commands. 




shell_dict_cmd_handler 



...



Dictionary triplets: (command_syntax, value, helper). Value will be passed to the _handler as user data.



Example usage: staticintmy_handler(conststructshell*sh,
size_targc,char**argv,void*data)
{
intval=(int)data;

shell_print(sh,"(syntax,value):(%s,%d)",argv[0],val);
return0;
}

SHELL_SUBCMD_DICT_SET_CREATE(sub_dict_cmds,my_handler,
(value_0,0,"value0"),(value_1,1,"value1"),
(value_2,2,"value2"),(value_3,3,"value3")
);
SHELL_CMD_REGISTER(dictionary,&sub_dict_cmds,NULL,NULL);
